const data = $input.first().json;
return (data.results || []).filter((r) => r.channelId).map((r) => ({ json: {
  channelId: r.channelId,
  channelTitle: r.channelTitle || null,
  channelHandle: r.channelHandle || null,
  channelVerified: !!r.channelVerified,
  videoId: r.videoId || null,
  videoTitle: r.title || null,
  viewCountText: r.viewCountText || null,
  publishedTimeText: r.publishedTimeText || null,
} }));

function parseViews(t) {
  if (!t) return 0;
  const s = String(t).toUpperCase().replace(/,/g, '');
  const num = parseFloat(s);
  if (isNaN(num)) return 0;
  if (s.indexOf('B') > -1) return Math.round(num * 1e9);
  if (s.indexOf('M') > -1) return Math.round(num * 1e6);
  if (s.indexOf('K') > -1) return Math.round(num * 1e3);
  return Math.round(num);
}
function popPoints(v) { return v >= 1e7 ? 5 : v >= 1e6 ? 4 : v >= 1e5 ? 3 : v >= 1e4 ? 2 : v > 0 ? 1 : 0; }
const byChannel = {};
for (const it of $input.all()) {
  const d = it.json; if (!d.channelId) continue;
  const k = d.channelId;
  if (!byChannel[k]) byChannel[k] = { channelId: k, channelTitle: d.channelTitle, channelHandle: d.channelHandle, verified: !!d.channelVerified, appearances: 0, maxViews: 0, sampleVideos: [] };
  const c = byChannel[k];
  c.appearances += 1;
  c.verified = c.verified || !!d.channelVerified;
  const v = parseViews(d.viewCountText);
  if (v > c.maxViews) c.maxViews = v;
  if (c.sampleVideos.length < 3) c.sampleVideos.push({ title: d.videoTitle, videoId: d.videoId, url: 'https://www.youtube.com/watch?v=' + d.videoId, views: d.viewCountText });
}
const ranked = Object.keys(byChannel).map((k) => {
  const c = byChannel[k];
  c.score = c.appearances * 10 + (c.verified ? 5 : 0) + popPoints(c.maxViews);
  return c;
}).sort((a, b) => (b.score - a.score) || (b.appearances - a.appearances) || (b.maxViews - a.maxViews));
return ranked.map((c, i) => ({ json: Object.assign({}, c, { rank: i + 1 }) }));

const c = $json;
const channelUrl = c.channelHandle ? ('https://www.youtube.com/' + c.channelHandle) : ('https://www.youtube.com/channel/' + c.channelId);
return { json: {
  rank: c.rank,
  channel: c.channelTitle,
  handle: c.channelHandle || null,
  channelUrl,
  verified: !!c.verified,
  appearances: c.appearances,
  topViews: c.maxViews,
  score: c.score,
  sampleVideos: c.sampleVideos,
  note: 'Prospect for discovery/research only — verify fit manually. This workflow performs no outreach or contact.',
} };
